namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public static class RecipeStore
{
    private static readonly List<Recipe> _recipes =
    [
        new() { Id = 1, Title = "Spaghetti Carbonara", Category = "Pasta", Ingredients = "Spaghetti, Eggs, Pancetta, Parmesan, Black Pepper", Steps = "1. Cook pasta\n2. Fry pancetta\n3. Mix eggs and cheese\n4. Combine all off heat", AverageRating = 4.5, RatingCount = 12 },
        new() { Id = 2, Title = "Chicken Tikka Masala", Category = "Curries", Ingredients = "Chicken, Yogurt, Tomato Sauce, Garam Masala, Cream", Steps = "1. Marinate chicken\n2. Grill chicken\n3. Make sauce\n4. Combine and simmer", AverageRating = 4.8, RatingCount = 20 },
        new() { Id = 3, Title = "Caesar Salad", Category = "Salads", Ingredients = "Romaine Lettuce, Croutons, Parmesan, Caesar Dressing, Anchovies", Steps = "1. Wash and chop lettuce\n2. Make dressing\n3. Toss with croutons and cheese", AverageRating = 3.9, RatingCount = 8 },
        new() { Id = 4, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "Dark Chocolate, Butter, Eggs, Sugar, Flour", Steps = "1. Melt chocolate and butter\n2. Whisk eggs and sugar\n3. Fold together with flour\n4. Bake 12 min at 220°C", AverageRating = 4.7, RatingCount = 15 },
        new() { Id = 5, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground Beef, Taco Shells, Lettuce, Tomato, Cheese, Salsa", Steps = "1. Brown beef with seasoning\n2. Warm shells\n3. Assemble with toppings", AverageRating = 4.2, RatingCount = 10 },
        new() { Id = 6, Title = "Mushroom Risotto", Category = "Pasta", Ingredients = "Arborio Rice, Mushrooms, Onion, White Wine, Parmesan, Stock", Steps = "1. Sauté mushrooms\n2. Toast rice\n3. Add stock gradually\n4. Finish with parmesan", AverageRating = 4.4, RatingCount = 7 },
        new() { Id = 7, Title = "Greek Salad", Category = "Salads", Ingredients = "Cucumber, Tomato, Red Onion, Olives, Feta, Olive Oil", Steps = "1. Chop vegetables\n2. Combine in bowl\n3. Add feta and olives\n4. Dress with olive oil", AverageRating = 4.0, RatingCount = 5 },
        new() { Id = 8, Title = "Tiramisu", Category = "Desserts", Ingredients = "Mascarpone, Espresso, Ladyfingers, Cocoa, Eggs, Sugar", Steps = "1. Make espresso and cool\n2. Whisk egg yolks with sugar\n3. Fold in mascarpone\n4. Layer with dipped ladyfingers", AverageRating = 4.9, RatingCount = 22 },
    ];

    public static IReadOnlyList<Recipe> All => _recipes;

    public static IEnumerable<string> Categories => _recipes.Select(r => r.Category).Distinct().Order();

    public static IEnumerable<Recipe> ByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase));

    public static Recipe? GetById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public static void Add(Recipe recipe)
    {
        recipe.Id = _recipes.Count > 0 ? _recipes.Max(r => r.Id) + 1 : 1;
        _recipes.Add(recipe);
    }

    public static void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is null) return;
        var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
        recipe.RatingCount++;
        recipe.AverageRating = totalStars / recipe.RatingCount;
    }
}

@page "/recipes"
@page "/recipes/{Category}"
@using RecipeShare.Models

<PageTitle>Recipes - @(Category ?? "All")</PageTitle>

<h1>@(Category ?? "All Recipes")</h1>

@if (Category is null)
{
    <p>Select a category to browse recipes:</p>
    <ul>
        @foreach (var cat in RecipeStore.Categories)
        {
            <li><a href="recipes/@cat">@cat</a></li>
        }
    </ul>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="recipes">All Categories</a></li>
            <li class="breadcrumb-item active">@Category</li>
        </ol>
    </nav>

    var recipes = RecipeStore.ByCategory(Category).ToList();

    @if (recipes.Count == 0)
    {
        <p>No recipes found in this category.</p>
    }
    else
    {
        <div class="list-group">
            @foreach (var recipe in recipes)
            {
                <a href="recipe/@recipe.Id" class="list-group-item list-group-item-action">
                    <div class="d-flex w-100 justify-content-between">
                        <h5 class="mb-1">@recipe.Title</h5>
                        <small>@recipe.AverageRating.ToString("F1") ★ (@recipe.RatingCount ratings)</small>
                    </div>
                </a>
            }
        </div>
    }
}

@code {
    [Parameter]
    public string? Category { get; set; }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Models

<PageTitle>@(recipe?.Title ?? "Recipe Not Found")</PageTitle>

@if (recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="recipes">All Categories</a></li>
            <li class="breadcrumb-item"><a href="recipes/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <span class="badge bg-secondary">@recipe.Category</span>
    <p class="text-muted mt-2">@recipe.AverageRating.ToString("F1") ★ from @recipe.RatingCount ratings</p>

    <h3 class="mt-4">Ingredients</h3>
    <ul>
        @foreach (var ingredient in recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            var text = step.TrimStart();
            if (text.Length > 2 && text[1] == '.' && char.IsDigit(text[0]))
                text = text[2..].TrimStart();
            else if (text.Length > 3 && text[2] == '.' && char.IsDigit(text[0]) && char.IsDigit(text[1]))
                text = text[3..].TrimStart();
            <li>@text</li>
        }
    </ol>

    <h3>Rate This Recipe</h3>
    <StarRating RecipeId="recipe.Id" />
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnInitialized()
    {
        recipe = RecipeStore.GetById(Id);
    }
}

